class Solution {
public:
    vector<int> getRow(int rowIndex) {
        vector<int> row = {1};
        for (int i = 1; i <= rowIndex; i++) {
            for (int j = i - 1; j >= 1; j--)
                row[j] += row[j - 1];
            row.push_back(1);
        }
        return row;
    }
};
